/**
 * Regenerate content/manifest.json — the optional index the app uses for fast,
 * integrity-checked, incremental sync. Run by CI on merge to main; contributors
 * do NOT edit the manifest by hand.
 *
 *   node scripts/generate-manifest.mjs
 */

import { createHash } from 'node:crypto';
import { execSync } from 'node:child_process';
import { readFileSync, readdirSync, writeFileSync, existsSync, statSync } from 'node:fs';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const here = dirname(fileURLToPath(import.meta.url));
const root = join(here, '..');
const contentDir = join(root, 'content');

const TARGETS = [
  { dir: 'glossary', type: 'glossary' },
  { dir: 'questions', type: 'question' },
  { dir: 'decks', type: 'card' },
  { dir: 'guides', type: 'guide' },
  { dir: 'sequences', type: 'sequence' },
  { dir: 'cases', type: 'case' },
  { dir: 'pointclick', type: 'pointclick' },
];

/** Last git commit time for a file (ISO), or file mtime as a fallback. */
function updatedAt(absPath, repoRelPath) {
  try {
    const out = execSync(`git log -1 --format=%cI -- "${repoRelPath}"`, { cwd: root, stdio: ['ignore', 'pipe', 'ignore'] })
      .toString()
      .trim();
    if (out) return out;
  } catch {
    // not a git repo yet / file untracked
  }
  return statSync(absPath).mtime.toISOString();
}

const files = [];
const totals = { glossary: 0, question: 0, card: 0, guide: 0, sequence: 0, case: 0, pointclick: 0 };

for (const { dir, type } of TARGETS) {
  const full = join(contentDir, dir);
  if (!existsSync(full)) continue;
  for (const name of readdirSync(full).filter((f) => f.endsWith('.json')).sort()) {
    const abs = join(full, name);
    const rel = `content/${dir}/${name}`;
    const bytes = readFileSync(abs);
    let count = 0;
    try {
      const arr = JSON.parse(bytes.toString('utf8'));
      count = Array.isArray(arr) ? arr.length : 0;
    } catch {
      count = 0;
    }
    files.push({
      path: rel,
      type,
      count,
      sha256: createHash('sha256').update(bytes).digest('hex'),
      updatedAt: updatedAt(abs, rel),
    });
    totals[type] += count;
  }
}

const manifest = {
  manifestVersion: 1,
  generatedAt: new Date().toISOString(),
  note: 'Generated by CI on merge to main. The app may use this for fast, cached, integrity-checked sync. It is OPTIONAL — the app can also discover files by listing the content/ subfolders via the GitHub Contents API. Contributors do NOT edit this file by hand.',
  files,
  totals,
};

writeFileSync(join(contentDir, 'manifest.json'), JSON.stringify(manifest, null, 2) + '\n');
console.log(
  `✓ Wrote content/manifest.json — ${files.length} files: ${totals.glossary} terms / ${totals.question} questions / ${totals.card} cards / ${totals.guide} guides / ${totals.sequence} sequences / ${totals.case} cases / ${totals.pointclick} point-click.`,
);
